// Input Validation & Normalization
// Extracts marketing data from the universal contract payload
// Validates required fields and normalizes input data

const items = $input.all();
const validatedItems = [];

for (const item of items) {
  const contract = item.json;

  // Extract payload (marketing-specific data)
  const payload = contract.payload || {};

  // Validate required fields in payload
  const requiredFields = ['objective', 'target_market', 'product_context'];
  const missingFields = requiredFields.filter(field => !payload[field]);

  if (missingFields.length > 0) {
    throw new Error(`Missing required payload fields: ${missingFields.join(', ')}`);
  }

  // Extract mode from contract (not payload)
  const mode = contract.mode || 'simulation';

  // Validate mode is valid
  const validModes = ['simulation', 'execute'];
  if (!validModes.includes(mode)) {
    throw new Error(`Invalid mode: ${mode}. Must be one of: ${validModes.join(', ')}`);
  }

  // Generate marketing_id (UUID v4)
  const marketing_id = `marketing_${Date.now()}_${Math.random().toString(36).substring(2, 15)}`;

  // Get execution metadata
  const timestamp = new Date().toISOString();
  const caller_workflow = contract.audit?.workflow_id || 'unknown';

  // Normalize objectives (ensure it's an array)
  let normalizedObjectives = payload.objective;
  if (typeof normalizedObjectives === 'string') {
    normalizedObjectives = [normalizedObjectives];
  }

  // Normalize target market data
  const normalizedMarket = {
    primary: payload.target_market.primary || payload.target_market,
    secondary: payload.target_market.secondary || [],
    demographics: payload.target_market.demographics || {},
    psychographics: payload.target_market.psychographics || {}
  };

  // Build validated and normalized output
  const validatedItem = {
    // Original contract fields (pass through)
    request_id: contract.request_id,
    mode: mode,
    confidence: contract.confidence,
    risk_level: contract.risk_level,

    // Marketing-specific fields from payload
    objective: normalizedObjectives,
    target_market: normalizedMarket,
    product_context: payload.product_context,

    // Metadata
    marketing_id: marketing_id,
    timestamp: timestamp,
    caller_workflow: caller_workflow,
    approval_required: true,

    // Additional context if provided in payload
    budget: payload.budget || null,
    timeline: payload.timeline || null,
    constraints: payload.constraints || [],
    brand_guidelines: payload.brand_guidelines || {},

    // Test mode flag
    test_mode: contract.test_mode || false
  };

  validatedItems.push({ json: validatedItem });
}

return validatedItems;

// Merge content from CMO agent output into publish-ready draft structure
// Extract all claims for CREA validation

const cmoOutput = $input.first().json;

// Initialize the publish-ready draft structure
const publishDraft = {
  metadata: {
    campaignId: cmoOutput.campaignId || `campaign_${Date.now()}`,
    createdAt: new Date().toISOString(),
    status: 'pending_validation'
  },
  content: {
    copy: {},
    creatives: {},
    seo: {}
  },
  claims: [],
  validationRequired: true
};

// Extract copy content
if (cmoOutput.copy) {
  publishDraft.content.copy = {
    headline: cmoOutput.copy.headline || '',
    subheadline: cmoOutput.copy.subheadline || '',
    bodyText: cmoOutput.copy.bodyText || '',
    callToAction: cmoOutput.copy.callToAction || '',
    additionalCopy: cmoOutput.copy.additionalCopy || []
  };
}

// Extract creative assets
if (cmoOutput.creatives) {
  publishDraft.content.creatives = {
    images: cmoOutput.creatives.images || [],
    videos: cmoOutput.creatives.videos || [],
    graphics: cmoOutput.creatives.graphics || [],
    designSpecs: cmoOutput.creatives.designSpecs || {}
  };
}

// Extract SEO metadata
if (cmoOutput.seo) {
  publishDraft.content.seo = {
    title: cmoOutput.seo.title || '',
    description: cmoOutput.seo.description || '',
    keywords: cmoOutput.seo.keywords || [],
    metaTags: cmoOutput.seo.metaTags || {},
    structuredData: cmoOutput.seo.structuredData || {}
  };
}

// Extract all claims for CREA validation
// Claims can be found in various parts of the content
const extractClaims = (text) => {
  if (!text) return [];

  // Pattern to identify potential claims (statements about product benefits, features, performance)
  const claimPatterns = [
    /\b(best|top|leading|#1|first|only|guaranteed|proven|clinically tested)\b/gi,
    /\b(\d+%|\d+x)\s+(better|faster|more|improved|increase|decrease)\b/gi,
    /\b(reduces|eliminates|prevents|cures|treats)\s+\w+/gi
  ];

  const foundClaims = [];
  claimPatterns.forEach(pattern => {
    const matches = text.match(pattern);
    if (matches) {
      matches.forEach(match => {
        foundClaims.push({
          text: match,
          context: text.substring(Math.max(0, text.indexOf(match) - 50), Math.min(text.length, text.indexOf(match) + 100)),
          type: 'auto_detected',
          requiresValidation: true
        });
      });
    }
  });

  return foundClaims;
};

// Collect claims from all text content
const allTextContent = [
  publishDraft.content.copy.headline,
  publishDraft.content.copy.subheadline,
  publishDraft.content.copy.bodyText,
  publishDraft.content.copy.callToAction,
  ...(publishDraft.content.copy.additionalCopy || []),
  publishDraft.content.seo.title,
  publishDraft.content.seo.description
].filter(Boolean).join(' ');

publishDraft.claims = extractClaims(allTextContent);

// Add manually specified claims if present in CMO output
if (cmoOutput.claims && Array.isArray(cmoOutput.claims)) {
  cmoOutput.claims.forEach(claim => {
    publishDraft.claims.push({
      text: claim.text || claim,
      context: claim.context || '',
      type: 'manual',
      requiresValidation: true
    });
  });
}

// Add claim count to metadata
publishDraft.metadata.claimCount = publishDraft.claims.length;
publishDraft.metadata.requiresCREAValidation = publishDraft.claims.length > 0;

return { json: publishDraft };

